module top_module(clk,reset,R,S,Out);input reset, clk, R, S;
	 output Out;
	 reg   ff_dataVal;

	 always @(posedge clk, negedge reset)
		if(!reset)
			ff_dataVal<=0;
		else if(R)
			ff_dataVal<=0;
		else if(S)
			ff_dataVal<=1;
		else 
			ff_dataVal<=ff_dataVal;

		assign Out=ff_dataVal;

	 endmodule
